import { useNavigate } from "react-router-dom"
export type Botao={
    nome:string;
    action:()=>void;  
}
export const PageHomeUsuario = () => {
    const navigation=useNavigate()
const botoes:Botao[]=[
    {nome:"Agendar", action:()=>{navigation("/novoAgendamento")}},
    {nome:"Meus Agendamentos", action:()=>{navigation("usuario/agendamento")}},                
]
    return(
        <div>
            <h1>Home Usuário</h1>
            {botoes.map((botao)=>(
            <div onClick={botao.action} style={{border:"1px solid black", width:"200px", margin:"10px", padding:"10px", cursor:"pointer", textAlign:"center"}}>
                {botao.nome}
            </div>))}
        </div>
    )
}
